SELECT COUNT(*) AS total_configurations
FROM software_configurations
WHERE software_type = 'Data Acquisition';

SELECT experiment_id, COUNT(run_id) AS total_runs
FROM lhrs_runs
GROUP BY experiment_id;

SELECT run_number, beam_energy
FROM lhrs_runs
WHERE detector_status = 'operational';

SELECT start_time
FROM software_used
WHERE software_type = 'Data Analysis';

SELECT hardware_type, COUNT(*) AS configuration_count
FROM hardware_configurations
GROUP BY hardware_type;

SELECT COUNT(run_id) AS run_count
FROM lhrs_runs
WHERE experiment_id = 0 AND beam_energy = '1000.0';
